import React, { useEffect, useState } from "react";
import axios from "axios";

export default function MealPlan() {
  const [plans, setPlans] = useState([]);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    axios
      .get("http://localhost:5000/api/dietplan/my-plans", {
        headers: {
          Authorization: "Bearer " + localStorage.getItem("token"),
        },
      })
      .then((res) => {
        setPlans(res.data);
        setLoading(false);
      })
      .catch((err) => {
        console.error(err);
        setLoading(false);
      });
  }, []);

  if (loading) {
    return <h4 className="text-center mt-5">Loading...</h4>;
  }

  if (plans.length === 0) {
    return <h4 className="text-center mt-5">No Meal Plans Yet</h4>;
  }

  return (
    <div className="container my-4">
      <h2 className="mb-4 text-center">Your AI Meal Plan</h2>

      {plans.map((plan, index) => (
        <div key={index} className="card mb-4 shadow">
          <div className="card-body">
            <h4>{plan.patientName}</h4>

            <p><strong>Condition:</strong> {plan.condition}</p>
            <p><strong>Goal:</strong> {plan.goal}</p>
            <p><strong>Calories:</strong> {plan.calories} kcal</p>

            {/* MEALS */}
            {plan.meals && typeof plan.meals === "object" ? (
              Object.entries(plan.meals).map(([mealTime, items]) => (
                <div key={mealTime} className="mb-3">
                  <h5 className="text-primary text-capitalize">{mealTime}</h5>

                  {Array.isArray(items) ? (
                    <ul>
                      {items.map((food, i) => (
                        <li key={i}>
                          {food.item
                            ? `${food.item} — ${food.quantity}`
                            : food}
                        </li>
                      ))}
                    </ul>
                  ) : (
                    <p>Meal data unavailable</p>
                  )}
                </div>
              ))
            ) : (
              <p>Invalid meal format</p>
            )}

            {/* AVOID */}
            {Array.isArray(plan.avoid) && plan.avoid.length > 0 && (
              <>
                <h6 className="text-danger">Foods to Avoid</h6>
                <ul>
                  {plan.avoid.map((a, i) => (
                    <li key={i}>{a}</li>
                  ))}
                </ul>
              </>
            )}

            {/* NOTES */}
            {Array.isArray(plan.notes) && plan.notes.length > 0 && (
              <>
                <h6 className="text-success">Health Notes</h6>
                <ul>
                  {plan.notes.map((n, i) => (
                    <li key={i}>{n}</li>
                  ))}
                </ul>
              </>
            )}
          </div>
        </div>
      ))}
    </div>
  );
}
